INSERT INTO `finance_cards` VALUES (1,'Sanaa Business Debit Card',NULL,'{\"FX Markup\": \"2.5%\", \"Monthly Fee\": \"UGX 0\", \"Card Issuance\": \"UGX 25,000\", \"POS Transactions\": \"Free\", \"Online Transactions\": \"Free\", \"ATM Withdrawal (Uganda)\": \"UGX 2,500\", \"ATM Withdrawal (International)\": \"3%\"}','[\"Instant issuance\", \"Works at any Visa ATM in Uganda\", \"Online & in-store payments\", \"Contactless (tap to pay)\", \"Real-time spending alerts\", \"Freeze/unfreeze via app\", \"Works with Stanbic, Centenary, dfcu ATMs\"]','Available to all Growth, Business, and Enterprise plan users. Valid Ugandan National ID required.',NULL,NULL,'published','2025-12-06 01:02:37','2025-12-06 01:02:37'),(2,'Sanaa Virtual Card',NULL,'{\"FX Markup\": \"2.5%\", \"Monthly Fee\": \"UGX 0\", \"Card Creation\": \"Free\", \"Card Replacement\": \"Free\", \"Online Transactions\": \"Free\"}','[\"Create instantly in the app\", \"Perfect for online purchases\", \"Single-use or recurring options\", \"Custom spending limits\", \"Auto-lock after transaction\", \"Great for subscriptions (AWS, Google, etc.)\", \"Multiple cards per account\"]','Available to all Sanaa Finance users on any plan.',NULL,NULL,'published','2025-12-06 01:02:37','2025-12-06 01:02:37'),(3,'Sanaa Staff Expense Card',NULL,'{\"Monthly Fee\": \"UGX 0\", \"Card Issuance\": \"UGX 15,000/card\", \"Minimum Cards\": \"5 cards\", \"All Transactions\": \"Free\"}','[\"Issue cards to employees\", \"Set spending limits per card\", \"Category restrictions (fuel only, etc.)\", \"Real-time expense tracking\", \"Receipt capture via mobile\", \"Automatic expense reports\", \"Instant freeze for lost cards\"]','Available to Business and Enterprise plan users with 5+ employees.',NULL,NULL,'published','2025-12-06 01:02:37','2025-12-06 01:02:37');
