INSERT INTO `finance_communities` VALUES (1,'SMEs & Retailers','[\"Accept Mobile Money payments\", \"Pay suppliers efficiently\", \"Access working capital\", \"Manage cash flow\", \"URA tax compliance\"]','[\"No monthly fees on Starter plan\", \"1.5% collection fee (lowest in Uganda)\", \"Same-day settlements\", \"Business loans from UGX 500K\", \"Free business account\"]',NULL,1,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(2,'SACCOs & Credit Unions','[\"Member account management\", \"Share capital tracking\", \"Loan origination & recovery\", \"URBRA compliance reporting\", \"Dividend distribution\"]','[\"Complete SACCO management system\", \"Mobile Money collection for members\", \"Automated loan recovery\", \"URBRA-ready reports\", \"Member mobile app included\"]',NULL,2,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(3,'Investment Clubs & Chamas','[\"Pool funds from members\", \"Track contributions\", \"Vote on investments\", \"Distribute returns fairly\", \"Transparent record keeping\"]','[\"Group account with multi-signatory\", \"Contribution tracking & reminders\", \"Investment voting via app\", \"Automated profit sharing\", \"Full audit trail\"]',NULL,3,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(4,'Schools & Educational Institutions','[\"Collect school fees digitally\", \"Track payments per student\", \"Pay staff salaries\", \"Manage supplier payments\", \"Generate financial reports\"]','[\"Mobile Money fee collection\", \"Automatic SMS receipts to parents\", \"Student balance tracking\", \"Bulk salary disbursement\", \"Term-wise financial reports\"]',NULL,4,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(5,'Solo Entrepreneurs & Freelancers','[\"Separate business from personal\", \"Professional invoicing\", \"Accept payments easily\", \"Track income & expenses\", \"Build credit history\"]','[\"Free business account forever\", \"Invoice generator included\", \"Payment links & QR codes\", \"Expense categorization\", \"Qualify for loans based on activity\"]',NULL,5,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(6,'Soko24 Marketplace Sellers','[\"Instant access to sales revenue\", \"Finance inventory purchases\", \"Understand sales performance\", \"Scale business operations\", \"Manage multiple product lines\"]','[\"Instant settlement of Soko24 sales\", \"Inventory financing loans\", \"Sales analytics dashboard\", \"Automatic tax calculations\", \"Priority seller support\"]',NULL,6,1,'2025-12-06 01:02:37','2025-12-06 01:02:37');
