INSERT INTO `finance_pages` VALUES (1,'Sanaa Finance: Banking Where African Businesses Thrive','overview','{\"blocks\": [{\"html\": \"<h2>Welcome to Sanaa Finance</h2><p>Sanaa Finance is Uganda\'s leading digital banking platform built specifically for SMEs, SACCOs, investment clubs, schools, and solo entrepreneurs. We understand the unique challenges of running a business in Uganda and have designed our platform to help you succeed.</p>\", \"type\": \"richtext\"}, {\"html\": \"<h3>What We Offer</h3><ul><li><strong>Digital Wallets:</strong> Accept payments via MTN Mobile Money, Airtel Money, and bank transfers</li><li><strong>Instant Payments:</strong> Pay suppliers, staff, and utilities in seconds</li><li><strong>Savings & Investments:</strong> Earn competitive interest on idle funds</li><li><strong>Business Loans:</strong> Access working capital based on your transaction history</li><li><strong>Sanaa Cards:</strong> Physical and virtual cards for business expenses</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Built for Uganda</h3><p>We integrate seamlessly with MTN MoMo, Airtel Money, and the Soko24 marketplace. Our platform is compliant with Bank of Uganda regulations and provides tools for URA tax remittance, NSSF contributions, and URBRA reporting for SACCOs.</p>\", \"type\": \"richtext\"}]}','published',NULL,'Sanaa Finance: Digital Banking for Ugandan Businesses','Discover Sanaa Finance: digital wallets, instant payments, savings & investments, loans and Sanaa Cards for African businesses.',NULL,NULL,NULL,1,21,21,NULL,'2025-11-08 19:10:23','2025-12-06 01:02:37'),(2,'Mobile Money Integration','mobile-money-integration','{\"blocks\": [{\"html\": \"<h2>Seamless Mobile Money Integration</h2><p>Accept payments from your customers via MTN Mobile Money and Airtel Money directly into your Sanaa Finance account. Instant settlement means your money is available immediately.</p>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Collection Features</h3><ul><li>Generate payment links and QR codes</li><li>USSD collection codes for offline payments</li><li>Bulk collection for schools and SACCOs</li><li>Automated reconciliation</li><li>Real-time SMS notifications</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Payout Features</h3><ul><li>Single and bulk payouts</li><li>Scheduled payments</li><li>Supplier payment automation</li><li>Payroll disbursement</li><li>Flat UGX 500 fee per payout</li></ul>\", \"type\": \"richtext\"}]}','published',NULL,'Mobile Money Integration - MTN MoMo & Airtel Money','Accept MTN Mobile Money and Airtel Money payments instantly with Sanaa Finance. Seamless integration for Ugandan businesses.',NULL,NULL,NULL,1,NULL,NULL,NULL,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(3,'SACCO Management System','sacco-management','{\"blocks\": [{\"html\": \"<h2>Complete SACCO Management Solution</h2><p>Sanaa Finance provides a comprehensive platform for Savings and Credit Cooperative Organizations (SACCOs) in Uganda. Manage members, shares, loans, and compliance all in one place.</p>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Member Management</h3><ul><li>Digital member registration with KYC</li><li>Share capital tracking</li><li>Contribution collection via Mobile Money</li><li>Member statements and passbooks</li><li>Mobile app for members</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Loan Management</h3><ul><li>Loan application and approval workflows</li><li>Interest calculation (reducing balance, flat rate)</li><li>Automated loan recovery from Mobile Money</li><li>Guarantor management</li><li>Defaulter tracking and notifications</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>URBRA Compliance</h3><ul><li>Automated regulatory reports</li><li>Financial statements generation</li><li>Audit trail for all transactions</li><li>Annual return preparation</li></ul>\", \"type\": \"richtext\"}]}','published',NULL,'SACCO Management System Uganda - Sanaa Finance','Complete SACCO management software for Ugandan cooperatives. Member management, loans, URBRA compliance reports.',NULL,NULL,NULL,1,NULL,NULL,NULL,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(4,'School Fee Collection System','school-fee-collection','{\"blocks\": [{\"html\": \"<h2>Digital School Fee Collection</h2><p>Make school fee collection effortless for both your institution and parents. Accept payments via Mobile Money with automatic reconciliation and instant receipts.</p>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Features for Schools</h3><ul><li>Student database management</li><li>Fee structure configuration by class/term</li><li>Payment tracking per student</li><li>Automatic SMS receipts to parents</li><li>Outstanding balance reminders</li><li>Financial reports by term/class</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Convenient for Parents</h3><ul><li>Pay via MTN MoMo or Airtel Money</li><li>No need to visit school premises</li><li>Instant payment confirmation</li><li>View payment history on mobile</li><li>Partial payments supported</li></ul>\", \"type\": \"richtext\"}]}','published',NULL,'School Fee Collection System Uganda','Digital school fee collection via Mobile Money. Automatic receipts, student tracking, and financial reports for Ugandan schools.',NULL,NULL,NULL,1,NULL,NULL,NULL,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(5,'Sanaa Business Loans','business-loans','{\"blocks\": [{\"html\": \"<h2>Working Capital When You Need It</h2><p>Get access to business loans based on your Sanaa Finance transaction history. No collateral required for qualified businesses. Fast approval, instant disbursement.</p>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Loan Features</h3><ul><li>Loans from UGX 500,000 to UGX 50,000,000</li><li>Repayment terms: 1-12 months</li><li>No collateral for qualified sellers</li><li>Decision within 24 hours</li><li>Instant disbursement to your account</li><li>Automated repayment from sales</li></ul>\", \"type\": \"richtext\"}, {\"html\": \"<h3>Who Qualifies?</h3><ul><li>Active Sanaa Finance users (3+ months)</li><li>Consistent transaction history</li><li>Soko24 sellers with good track record</li><li>SACCOs and investment clubs</li></ul>\", \"type\": \"richtext\"}]}','published',NULL,'Business Loans Uganda - Sanaa Finance','Get working capital loans for your Ugandan business. No collateral, fast approval, automatic repayment from sales.',NULL,NULL,NULL,1,NULL,NULL,NULL,'2025-12-06 01:02:37','2025-12-06 01:02:37');
/*!40000 ALTER TABLE `finance_pages` ENABLE KEYS */;
UNLOCK TABLES;

