INSERT INTO `finance_pricing_plans` VALUES (1,'Starter','Perfect for solo entrepreneurs and small businesses just getting started',0.00,0.00,'[\"Free business account\", \"MTN MoMo & Airtel Money collections\", \"Up to 50 transactions/month free\", \"Basic invoicing\", \"Mobile app access\", \"Email support\"]','[\"50 free transactions/month\", \"1 user\", \"Basic reports\"]',NULL,NULL,1,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(2,'Growth','For growing SMEs, retailers, and Soko24 sellers who need more power',75000.00,750000.00,'[\"Everything in Starter\", \"Unlimited transactions\", \"Physical & virtual Sanaa Cards\", \"Bulk payouts to suppliers\", \"Automated tax (URA) remittance\", \"Multi-user access (up to 5)\", \"Soko24 integration\", \"Priority WhatsApp support\"]','[\"Unlimited transactions\", \"5 users\", \"Advanced reports\"]',NULL,'Most Popular',2,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(3,'Business','For established businesses with higher volumes and complex needs',250000.00,2500000.00,'[\"Everything in Growth\", \"Dedicated account manager\", \"Custom card designs\", \"API access for integrations\", \"Expense management tools\", \"Multi-branch support\", \"Up to 20 team members\", \"Working capital loans eligibility\", \"Phone support\"]','[\"Unlimited everything\", \"20 users\", \"Custom reports\"]',NULL,NULL,3,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(4,'SACCO Pro','Complete solution for SACCOs, investment clubs, and cooperative societies',500000.00,5000000.00,'[\"Member management system\", \"Share capital tracking\", \"Loan origination & management\", \"Automated loan recovery\", \"Dividend calculation & distribution\", \"Mobile Money collection for members\", \"URBRA compliance reports\", \"AGM voting system\", \"Member mobile app\", \"Unlimited members\", \"Dedicated support team\"]','[\"Unlimited members\", \"Full SACCO features\", \"Compliance ready\"]',NULL,'For SACCOs',4,1,'2025-12-06 01:02:37','2025-12-06 01:02:37'),(5,'Enterprise','Custom solutions for large institutions, schools, and corporations',NULL,NULL,'[\"Everything in Business/SACCO Pro\", \"Custom integrations\", \"On-premise deployment option\", \"SLA guarantees (99.9% uptime)\", \"Dedicated infrastructure\", \"White-label options\", \"Custom compliance packages\", \"Training & onboarding\", \"24/7 phone support\"]','[\"Custom limits\", \"Unlimited users\", \"Enterprise SLA\"]',NULL,'Contact Us',5,1,'2025-12-06 01:02:37','2025-12-06 01:02:37');
