INSERT INTO `services` VALUES (1,'Sanaa Finance Implementation','Complete deployment of Sanaa Finance for SACCOs, MFIs, and money lenders. Includes data migration, system configuration, staff training, and go-live support. We digitise your member management, loan origination, collections, and URBRA compliance reporting.','fas fa-university',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07'),(2,'Soko24 POS & Marketplace Setup','End-to-end setup of Soko24 point-of-sale system for retailers and SMEs. Hardware installation, inventory configuration, pricing structure, staff training, and connection to the Soko24 marketplace for online sales.','fas fa-cash-register',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07'),(3,'Digital Transformation for SACCOs','Strategic consulting and implementation for SACCOs looking to modernise. Process mapping, digitisation roadmap, change management, and staff capacity building. Move from paper and WhatsApp to a fully digital operation.','fas fa-sync-alt',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07'),(4,'School & Education Programs','Complete education technology deployment including computer labs with Matic devices, EduOS school management system, digital fee collection, and teacher training programs. From kindergarten to university.','fas fa-graduation-cap',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07'),(5,'Logistics & Corridor Design','Courier process digitisation, warehouse management, and route planning using the Baraka logistics platform. Specialised in Uganda-DRC corridors and Asia-to-Africa import/export visibility.','fas fa-truck',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07'),(6,'Device Deployment & Support','Hardware rollout services for laptops, tablets, POS terminals, and custom devices. Includes procurement, configuration, deployment logistics, warranty support, and field engineer maintenance across all 134 Ugandan districts.','fas fa-laptop',NULL,1,'2025-12-06 01:35:07','2025-12-06 01:35:07');
/*!40000 ALTER TABLE `services` ENABLE KEYS */;
UNLOCK TABLES;

