INSERT INTO `services_page_settings` VALUES (1,'hero_eyebrow','Implementation & Deployment','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(2,'hero_title','Turning Products into Real Change','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(3,'hero_subtitle','From SACCO digitisation to SME POS deployments, we provide hands-on services that bring our products to life on the ground in Uganda, DRC, and beyond.','textarea','2025-12-06 01:56:51','2025-12-06 01:56:51'),(4,'hero_cta_primary_text','Book a Consultation','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(5,'hero_cta_secondary_text','View Services','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(6,'stat_1_value','2018','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(7,'stat_1_label','Founded','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(8,'stat_2_value','134','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(9,'stat_2_label','Districts Covered','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(10,'stat_3_value','37+','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(11,'stat_3_label','Financial Institutions','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(12,'stat_4_value','5','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(13,'stat_4_label','Countries','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(14,'services_eyebrow','What We Do','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(15,'services_title','Implementation Services','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(16,'services_subtitle','We don\'t just sell software — we deploy, configure, train, and support your team until you\'re running confidently.','textarea','2025-12-06 01:56:51','2025-12-06 01:56:51'),(17,'why_eyebrow','Why Sanaa','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(18,'why_title','Built for African Realities','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(19,'why_subtitle','We design around your power, network, and staff constraints — not against them.','textarea','2025-12-06 01:56:51','2025-12-06 01:56:51'),(20,'why_features','[{\"title\":\"Built for Africa\",\"description\":\"We design around your power, network, and staff constraints \\u2014 not against them.\",\"color\":\"emerald\"},{\"title\":\"Local + Global Expertise\",\"description\":\"Teams in Uganda & DRC, with partners in Europe, North America, China and across Africa.\",\"color\":\"blue\"},{\"title\":\"End-to-End Ecosystem\",\"description\":\"Software, devices, finance and logistics that work together \\u2014 not standalone tools.\",\"color\":\"purple\"},{\"title\":\"Training & Long-term Support\",\"description\":\"We don\'t just deploy and disappear; we train your people and stay available.\",\"color\":\"orange\"}]','json','2025-12-06 01:56:51','2025-12-06 01:56:51'),(21,'sectors_eyebrow','Who We Serve','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(22,'sectors_title','Trusted Across Sectors','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(23,'sectors','[{\"name\":\"SACCOs & MFIs\",\"color\":\"emerald\"},{\"name\":\"SMEs & Retailers\",\"color\":\"blue\"},{\"name\":\"Schools\",\"color\":\"purple\"},{\"name\":\"Logistics\",\"color\":\"orange\"},{\"name\":\"Agriculture\",\"color\":\"teal\"},{\"name\":\"NGOs\",\"color\":\"pink\"}]','json','2025-12-06 01:56:51','2025-12-06 01:56:51'),(24,'cta_eyebrow','Let\'s Talk','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(25,'cta_title','Ready to Get Started?','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(26,'cta_subtitle','Tell us about your SACCO, school, SME, or logistics operation. We\'ll recommend the right mix of Sanaa products and services for your needs.','textarea','2025-12-06 01:56:51','2025-12-06 01:56:51'),(27,'cta_primary_text','Book a Consultation','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(28,'cta_secondary_text','Explore Sanaa Finance','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(29,'cta_secondary_link','/finance','text','2025-12-06 01:56:51','2025-12-06 01:56:51'),(30,'cta_footer','Serving businesses across Uganda, Kenya, Tanzania, Rwanda, and DRC','text','2025-12-06 01:56:51','2025-12-06 01:56:51');
