INSERT INTO `team_members` VALUES (1,'Aguma I. Banks','Founder & CEO','Visionary leader building digital infrastructure across Africa.','team/yWIXk7Q0A60FJHKVA3P6cHb2ClcGWWZTKw75Vou9.png','2025-12-06 01:03:21','2025-12-06 01:20:32'),(2,'Nuwagaba Felix','COO',NULL,'team/MZNbhv36tmPICGS9pTRMgrt015cHlrmiOb5z8aZi.png','2025-12-06 01:22:28','2025-12-20 04:22:34'),(3,'NICOLE ARAME','CLO','Sanaa’s Chief Legal Officer safeguards our vision with strong governance, ethical leadership and smart risk management across all companies and regions.','team/J785I0XOBwCAvl0D5zVS1GV5dTUR8R1JmMJWRWFA.png','2025-12-06 01:25:47','2025-12-06 01:25:47'),(4,'Elie Le Potier','Senior Developer','Sanaa’s Senior Developer designs and builds scalable systems, mentors engineers, and turns bold product ideas into secure, high-quality code across platforms.','team/k7QSL3Z4TqdaBoPGQez1QxUGDotvmqeO5GmnQDg1.png','2025-12-06 01:26:51','2025-12-20 04:20:42'),(5,'Allen Mutabazi','Asst. Finance','Sanaa’s Assistant Finance supports budgeting, payments, and reporting, keeping records accurate, cashflows monitored, and leaders informed for smart decisions.','team/Ox72PVUT8vtb2UNPlqVOIdjP8ULkUGf6tIkVlMdX.png','2025-12-06 01:27:31','2025-12-06 01:27:31'),(6,'MpinDu Jp B.','Intl. Relations','Sanaa’s Internal Relations builds trust inside the company, improves communication, resolves conflicts, and keeps teams aligned with our mission and values.','team/s25ejfUhcALpA5tOzoOqToUxYY0bRCPPZTeIRhOk.png','2025-12-06 01:28:34','2025-12-06 01:28:34');
/*!40000 ALTER TABLE `team_members` ENABLE KEYS */;
UNLOCK TABLES;

